class SpanContext:
    """Represents a single span (unit of work) within a transaction."""
    
    def __init__(self, name, span_type, parent=None):
        self.name = name
        self.span_type = span_type
        self.parent = parent
        self.span_id = id(self)
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.status = 'success'
        self.metadata = {}
        self.stack_trace = []
        self.sql_query = None
        self.error = None
    
    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
    
    def set_error(self, error):
        self.status = 'error'
        self.error = {
            'type': type(error).__name__,
            'message': str(error),
        }
    
    def to_dict(self):
        result = {
            'name': self.name,
            'type': self.span_type,
            'span_id': self.span_id,
            'start_time': self.start_time,
            'duration_ms': self.duration_ms,
            'status': self.status,
            'metadata': self.metadata,
        }
        if self.sql_query:
            result['sql'] = self.sql_query
        if self.error:
            result['error'] = self.error
        if self.stack_trace:
            result['stack_trace'] = self.stack_trace
        return result


class TransactionContext:
    """Represents a transaction (top-level operation)."""
    
    def __init__(self, name, transaction_type='request'):
        self.name = name
        self.transaction_type = transaction_type
        self.transaction_id = id(self)
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.status = 'success'
        self.spans = []
        self.request_data = {}
        self.response_data = {}
        self.metadata = {}
        self.errors = []
    
    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
    
    def add_span(self, span):
        self.spans.append(span)
    
    def set_error(self, error):
        self.status = 'error'
        self.errors.append({
            'type': type(error).__name__,
            'message': str(error),
            'timestamp': time.time(),
        })
    
    def to_dict(self):
        return {
            'name': self.name,
            'type': self.transaction_type,
            'transaction_id': self.transaction_id,
            'start_time': datetime.fromtimestamp(self.start_time).isoformat(),
            'duration_ms': self.duration_ms,
            'status': self.status,
            'request': self.request_data,
            'response': self.response_data,
            'metadata': self.metadata,
            'spans': [s.to_dict() for s in self.spans],
            'errors': self.errors,
            'span_count': len(self.spans),
        }


