# --- Decorators for easy instrumentation ---

def trace_function(apm_client, span_type='function'):
    """Decorator to automatically trace function execution."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            with apm_client.span(f"{func.__module__}.{func.__qualname__}", span_type) as span:
                span.metadata['args_count'] = len(args)
                span.metadata['kwargs_keys'] = list(kwargs.keys())
                result = func(*args, **kwargs)
                return result
        return wrapper
    return decorator


def trace_sql(apm_client):
    """Decorator to trace SQL operations."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            query = args[0] if args else kwargs.get('query', 'unknown')
            params = args[1] if len(args) > 1 else kwargs.get('params', None)
            
            with apm_client.span(f"SQL: {query[:50]}...", 'db.sqlite') as span:
                span.sql_query = query
                span.metadata['params'] = str(params) if params else None
                start = time.time()
                try:
                    result = func(*args, **kwargs)
                    duration_ms = (time.time() - start) * 1000
                    apm_client.capture_sql(query, params, duration_ms)
                    return result
                except Exception as e:
                    duration_ms = (time.time() - start) * 1000
                    apm_client.capture_sql(query, params, duration_ms)
                    raise
        return wrapper
    return decorator


# --- Instrumented Database Layer ---

class InstrumentedDatabase:
    """SQLite database wrapper with APM instrumentation."""
    
    def __init__(self, db_path, apm_client):
        self.db_path = db_path
        self.apm = apm_client
        self.conn = None
    
    def connect(self):
        with self.apm.span('db.connect', 'db.sqlite') as span:
            self.conn = sqlite3.connect(self.db_path)
            self.conn.row_factory = sqlite3.Row
            span.metadata['db_path'] = self.db_path
            logger.info(f"Connected to database: {self.db_path}")
    
    def execute(self, query, params=None):
        with self.apm.span(f'db.query', 'db.sqlite') as span:
            span.sql_query = query
            span.metadata['params'] = str(params) if params else None
            
            start = time.time()
            cursor = self.conn.cursor()
            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)
            self.conn.commit()
            duration_ms = (time.time() - start) * 1000
            
            self.apm.capture_sql(query, params, duration_ms)
            span.metadata['rowcount'] = cursor.rowcount
            
            return cursor
    
    def fetchall(self, query, params=None):
        with self.apm.span('db.fetchall', 'db.sqlite') as span:
            span.sql_query = query
            
            start = time.time()
            cursor = self.conn.cursor()
            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)
            results = cursor.fetchall()
            duration_ms = (time.time() - start) * 1000
            
            self.apm.capture_sql(query, params, duration_ms)
            span.metadata['row_count'] = len(results)
            
            return [dict(row) for row in results]
    
    def fetchone(self, query, params=None):
        with self.apm.span('db.fetchone', 'db.sqlite') as span:
            span.sql_query = query
            
            start = time.time()
            cursor = self.conn.cursor()
            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)
            result = cursor.fetchone()
            duration_ms = (time.time() - start) * 1000
            
            self.apm.capture_sql(query, params, duration_ms)
            
            return dict(result) if result else None
    
    def close(self):
        if self.conn:
            with self.apm.span('db.close', 'db.sqlite'):
                self.conn.close()
                logger.info("Database connection closed")


# --- Instrumented HTTP-like Request Handler ---

class InstrumentedRequestHandler:
    """Simulated HTTP request handler with APM instrumentation."""
    
    def __init__(self, apm_client, db):
        self.apm = apm_client
        self.db = db
    
    def handle_request(self, method, path, headers=None, body=None):
        """Handle an incoming request with full APM tracing."""
        with self.apm.transaction(f"{method} {path}", 'request') as txn:
            # Capture request
            self.apm.capture_request(method, path, headers, body)
            txn.metadata['handler'] = 'InstrumentedRequestHandler'
            
            try:
                # Route to appropriate handler
                if path == '/api/users' and method == 'GET':
                    response = self._get_users()
                elif path == '/api/users' and method == 'POST':
                    response = self._create_user(body)
                elif path.startswith('/api/users/') and method == 'GET':
                    user_id = path.split('/')[-1]
                    response = self._get_user(user_id)
                elif path == '/api/slow-endpoint':
                    response = self._slow_endpoint()
                elif path == '/api/error-endpoint':
                    response = self._error_endpoint()
                else:
                    response = {'status': 404, 'body': {'error': 'Not Found'}}
                
                # Capture response
                self.apm.capture_response(
                    response['status'],
                    headers={'Content-Type': 'application/json'},
                    body=response['body']
                )
                
                return response
                
            except Exception as e:
                error_response = {
                    'status': 500,
                    'body': {'error': str(e), 'type': type(e).__name__}
                }
                self.apm.capture_response(500, body=error_response['body'])
                self.apm.capture_error(e, handled=True)
                return error_response
    
    def _get_users(self):
        with self.apm.span('handler.get_users', 'handler'):
            users = self.db.fetchall("SELECT * FROM users ORDER BY created_at DESC")
            return {'status': 200, 'body': {'users': users, 'count': len(users)}}
    
    def _create_user(self, body):
        with self.apm.span('handler.create_user', 'handler') as span:
            if not body or 'name' not in body or 'email' not in body:
                return {'status': 400, 'body': {'error': 'name and email required'}}
            
            # Validate input
            with self.apm.span('validation.user_input', 'validation'):
                name = body['name']
                email = body['email']
                if '@' not in email:
                    return {'status': 400, 'body': {'error': 'Invalid email format'}}
            
            # Insert user
            self.db.execute(
                "INSERT INTO users (name, email, created_at) VALUES (?, ?, ?)",
                (name, email, datetime.now().isoformat())
            )
            
            # Fetch created user
            user = self.db.fetchone(
                "SELECT * FROM users WHERE email = ?", (email,)
            )
            
            span.metadata['created_user_email'] = email
            return {'status': 201, 'body': {'user': user}}
    
    def _get_user(self, user_id):
        with self.apm.span('handler.get_user', 'handler') as span:
            span.metadata['user_id'] = user_id
            user = self.db.fetchone(
                "SELECT * FROM users WHERE id = ?", (user_id,)
            )
            if user:
                return {'status': 200, 'body': {'user': user}}
            return {'status': 404, 'body': {'error': 'User not found'}}
    
    def _slow_endpoint(self):
        """Simulates a slow endpoint for performance monitoring."""
        with self.apm.span('handler.slow_operation', 'handler'):
            # Simulate slow external API call
            with self.apm.span('external.api_call', 'external') as span:
                span.metadata['external_service'] = 'slow-api.example.com'
                time.sleep(0.5)  # Simulate 500ms external call
            
            # Simulate slow database query
            with self.apm.span('db.complex_query', 'db.sqlite') as span:
                span.sql_query = "SELECT complex aggregation query..."
                time.sleep(0.3)  # Simulate 300ms query
            
            # Simulate data processing
            with self.apm.span('processing.data_transform', 'processing'):
                time.sleep(0.2)  # Simulate 200ms processing
                result = {'processed': True, 'items': 1000}
            
            return {'status': 200, 'body': result}
    
    def _error_endpoint(self):
        """Simulates an endpoint that throws an error."""
        with self.apm.span('handler.error_operation', 'handler'):
            # Do some work before the error
            with self.apm.span('preprocessing', 'handler'):
                time.sleep(0.1)
            
            # This will raise an error
            raise ValueError("Something went wrong in the error endpoint!")


# --- Background Task Processor with APM ---

class InstrumentedTaskProcessor:
    """Background task processor with APM instrumentation."""
    
    def __init__(self, apm_client):
        self.apm = apm_client
    
    def process_task(self, task_name, task_data=None):
        """Process a background task with tracing."""
        with self.apm.transaction(f"task:{task_name}", 'background_task') as txn:
            txn.metadata['task_name'] = task_name
            txn.metadata['task_data'] = task_data
            
            try:
                if task_name == 'send_email':
                    return self._send_email(task_data)
                elif task_name == 'generate_report':
                    return self._generate_report(task_data)
                elif task_name == 'failing_task':
                    return self._failing_task(task_data)
                else:
                    return {'status': 'unknown_task'}
            except Exception as e:
                self.apm.capture_error(e)
                raise
    
    def _send_email(self, data):
        with self.apm.span('task.send_email', 'task'):
            # Simulate email template rendering
            with self.apm.span('email.render_template', 'template'):
                time.sleep(0.05)
            
            # Simulate SMTP connection
            with self.apm.span('email.smtp_send', 'external') as span:
                span.metadata['to'] = data.get('to', 'unknown')
                span.metadata['subject'] = data.get('subject', 'no subject')
                time.sleep(0.1)
            
            return {'status': 'sent', 'to': data.get('to')}
    
    def _generate_report(self, data):
        with self.apm.span('task.generate_report', 'task') as span:
            # Simulate data fetching
            with self.apm.span('report.fetch_data', 'db'):
                time.sleep(0.2)
                records = 5000
            
            # Simulate data processing
            with self.apm.span('report.process_data', 'processing') as proc_span:
                time.sleep(0.3)
                proc_span.metadata['records_processed'] = records
            
            # Simulate file generation
            with self.apm.span('report.generate_file', 'io') as file_span:
                time.sleep(0.15)
                file_span.metadata['file_format'] = 'PDF'
                file_span.metadata['file_size_kb'] = 2048
            
            span.metadata['total_records'] = records
            return {'status': 'generated', 'records': records}
    
    def _failing_task(self, data):
        with self.apm.span('task.failing', 'task'):
            time.sleep(0.05)
            raise RuntimeError("Task processing failed: insufficient resources")


# --- Flask Integration Example ---

def create_flask_app_with_apm():
    """
    Create a Flask app with elastic-apm integration.
    This shows how to integrate with a real web framework.
    """
    try:
        from flask import Flask, request, jsonify
        from elasticapm.contrib.flask import ElasticAPM
        
        app = Flask(__name__)
        
        app.config['ELASTIC_APM'] = {
            'SERVICE_NAME': APM_CONFIG['SERVICE_NAME'],
            'SECRET_TOKEN': APM_CONFIG['SECRET_TOKEN'],
            'SERVER_URL': APM_CONFIG['SERVER_URL'],
            'ENVIRONMENT': APM_CONFIG['ENVIRONMENT'],
            'CAPTURE_BODY': APM_CONFIG['CAPTURE_BODY'],
            'CAPTURE_HEADERS': APM_CONFIG['CAPTURE_HEADERS'],
            'COLLECT_LOCAL_VARIABLES': APM_CONFIG['COLLECT_LOCAL_VARIABLES'],
            'DEBUG': APM_CONFIG['DEBUG'],
            'TRANSACTION_SAMPLE_RATE': APM_CONFIG['TRANSACTION_SAMPLE_RATE'],
        }
        
        apm = ElasticAPM(app)
        
        @app.route('/api/health')
        def health():
            return jsonify({'status': 'healthy'})
        
        @app.route('/api/users', methods=['GET'])
        def get_users():
            return jsonify({'users': [], 'count': 0})
        
        logger.info("Flask app with Elastic APM created successfully")
        return app
        
    except ImportError:
        logger.info(
            "Flask or elastic-apm not available for Flask integration demo. "
            "Install with: pip install flask elastic-apm"
        )
        return None


# --- Main Demo ---

def setup_database(db):
    """Set up the demo database schema."""
    db.connect()
    db.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            email TEXT UNIQUE NOT NULL,
            created_at TEXT NOT NULL
        )
    """)
    db.execute("""
        CREATE TABLE IF NOT EXISTS orders (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            amount REAL NOT NULL,
            status TEXT DEFAULT 'pending',
            created_at TEXT NOT NULL,
            FOREIGN KEY (user_id) REFERENCES users(id)
        )
    """)


def run_demo():
    """Run the full APM demo."""
    print("\n" + "=" * 70)
    print("  APPLICATION PERFORMANCE MONITORING (APM) DEMO")
    print("=" * 70 + "\n")
    
    # Initialize APM client
    apm = APMClient(APM_CONFIG)
    
    # Initialize database
    db = InstrumentedDatabase(':memory:', apm)
    setup_database(db)
    
    # Initialize request handler
    handler = InstrumentedRequestHandler(apm, db)
    
    # Initialize task processor
    task_processor = InstrumentedTaskProcessor(apm)
    
    # --- Demo 1: Create Users ---
    print("\n--- Demo 1: Creating Users ---\n")
    
    users_to_create = [
        {'name': 'Alice Johnson', 'email': 'alice@example.com'},
        {'name': 'Bob Smith', 'email': 'bob@example.com'},
        {'name': 'Charlie Brown', 'email': 'charlie@example.com'},
    ]
    
    for user_data in users_to_create:
        response = handler.handle_request(
            'POST', '/api/users',
            headers={'Content-Type': 'application/json', 'Authorization': 'Bearer token123'},
            body=user_data
        )
        print(f"  Created user: {response['body']}")
    
    # --- Demo 2: Get Users ---
    print("\n--- Demo 2: Fetching All Users ---\n")
    
    response = handler.handle_request(
        'GET', '/api/users',
        headers={'Accept': 'application/json'}
    )
    print(f"  Users found: {response['body']['count']}")
    for user in response['body']['users']:
        print(f"    - {user['name']} ({user['email']})")
    
    # --- Demo 3: Get Single User ---
    print("\n--- Demo 3: Fetching Single User ---\n")
    
    response = handler.handle_request('GET', '/api/users/1')
    print(f"  User: {response['body']}")
    
    # --- Demo 4: 404 Request ---
    print("\n--- Demo 4: Not Found Request ---\n")
    
    response = handler.handle_request('GET', '/api/users/999')
    print(f"  Response: {response['body']}")
    
    # --- Demo 5: Slow Endpoint ---
    print("\n--- Demo 5: Slow Endpoint (Performance Test) ---\n")
    
    response = handler.handle_request('GET', '/api/slow-endpoint')
    print(f"  Response: {response['body']}")
    
    # --- Demo 6: Error Endpoint ---
    print("\n--- Demo 6: Error Endpoint ---\n")
    
    response = handler.handle_request('GET', '/api/error-endpoint')
    print(f"  Error Response: {response['body']}")
    
    # --- Demo 7: Invalid Request ---
    print("\n--- Demo 7: Invalid Request ---\n")
    
    response = handler.handle_request(
        'POST', '/api/users',
        body={'name': 'Invalid User'}  # Missing email
    )
    print(f"  Validation Error: {response['body']}")
    
    # --- Demo 8: Background Tasks ---
    print("\n--- Demo 8: Background Tasks ---\n")
    
    # Send email task
    result = task_processor.process_task('send_email', {
        'to': 'alice@example.com',
        'subject': 'Welcome!',
        'body': 'Welcome to our platform!'
    })
    print(f"  Email task: {result}")
    
    # Generate report task
    result = task_processor.process_task('generate_report', {
        'report_type': 'monthly_summary',
        'month': '2024-01'
    })
    print(f"  Report task: {result}")
    
    # Failing task
    try:
        task_processor.process_task('failing_task', {'data': 'test'})
    except RuntimeError as e:
        print(f"  Failing task caught: {e}")
    
    # --- Demo 9: Unknown Route ---
    print("\n--- Demo 9: Unknown Route ---\n")
    
    response = handler.handle_request('DELETE', '/api/unknown')
    print(f"  Response: {response['body']}")
    
    # --- Metrics Summary ---
    print("\n" + "=" * 70)
    print("  APM METRICS SUMMARY")
    print("=" * 70 + "\n")
    
    summary = apm.get_metrics_summary()
    print(f"  Total Transactions: {summary['total_transactions']}")
    print(f"  Total Spans: {summary['total_spans']}")
    print(f"  Total Duration: {summary['total_duration_ms']:.2f}ms")
    print(f"  Avg Duration: {summary['avg_duration_ms']:.2f}ms")
    print(f"  Error Count: {summary['error_count']}")
    print(f"  Error Rate: {summary['error_rate']:.1%}")
    
    print(f"\n  Transaction Details:")
    for txn in summary['transactions']:
        status_icon = '✓' if txn['status'] == 'success' else '✗'
        print(f"    {status_icon} {txn['name']}")
        print(f"      Duration: {txn['duration_ms']:.2f}ms | Spans: {txn['span_count']} | Status: {txn['status']}")
        if txn.get('request') and txn['request'].get('method'):
            print(f"      Request: {txn['request']['method']} {txn['request']['url']}")
        if txn.get('response') and txn['response'].get('status_code'):
            print(f"      Response: {txn['response']['status_code']}")
        if txn.get('errors'):
            for err in txn['errors']:
                print(f"      Error: {err['type']}: {err['message']}")
    
    # Export full metrics as JSON
    metrics_file = 'apm_metrics.json'
    with open(metrics_file, 'w') as f:
        json.dump(summary, f, indent=2, default=str)
    print(f"\n  Full metrics exported to: {metrics_file}")
    
    # Cleanup
    db.close()
    apm.shutdown()
    
    print("\n" + "=" * 70)
    print("  DEMO COMPLETE")
    print("=" * 70 + "\n")
    
    # Try to create Flask app
    flask_app = create_flask_app_with_apm()
    if flask_app:
        print("Flask app with Elastic APM is ready to run.")
        print("Start with: flask_app.run(debug=True)")


if __name__ == '__main__':
    run_demo()